import { describe, expect, it } from 'vitest';
import { createBaseType, createDateType, Type, type TypeBoxInfer } from '../type';

describe('schema/lib/type', () => {
  describe('createBaseType', () => {
    describe('with primitive types', () => {
      it('should validate strings', () => {
        const stringType = createBaseType(Type.String());

        expect(stringType.check('hello')).toBe(true);
        expect(stringType.check(123)).toBe(false);
        expect(stringType.check(null)).toBe(false);

        expect(stringType.parse('hello')).toBe('hello');
        expect(() => stringType.parse(123)).toThrow();

        expect(stringType.errors('hello')).toEqual([]);
        expect(stringType.errors(123).length).toBeGreaterThan(0);

        expect(stringType.decode('hello')).toBe('hello');
      });

      it('should validate numbers', () => {
        const numberType = createBaseType(Type.Number());

        expect(numberType.check(42)).toBe(true);
        expect(numberType.check(3.14)).toBe(true);
        expect(numberType.check('42')).toBe(false);
        expect(numberType.check(NaN)).toBe(false);

        expect(numberType.parse(42)).toBe(42);
        expect(() => numberType.parse('42')).toThrow();
      });

      it('should validate booleans', () => {
        const boolType = createBaseType(Type.Boolean());

        expect(boolType.check(true)).toBe(true);
        expect(boolType.check(false)).toBe(true);
        expect(boolType.check('true')).toBe(false);
        expect(boolType.check(1)).toBe(false);
      });

      it('should validate null', () => {
        const nullType = createBaseType(Type.Null());

        expect(nullType.check(null)).toBe(true);
        expect(nullType.check(undefined)).toBe(false);
        expect(nullType.check(0)).toBe(false);
      });

      it('should validate undefined', () => {
        const undefinedType = createBaseType(Type.Undefined());

        expect(undefinedType.check(undefined)).toBe(true);
        expect(undefinedType.check(null)).toBe(false);
      });
    });

    describe('with complex types', () => {
      it('should validate objects', () => {
        const objectType = createBaseType(
          Type.Object({
            name: Type.String(),
            age: Type.Number(),
          }),
        );

        expect(
          objectType.check({
            name: 'John',
            age: 30,
          }),
        ).toBe(true);
        expect(objectType.check({ name: 'John' })).toBe(false);
        expect(
          objectType.check({
            name: 123,
            age: 30,
          }),
        ).toBe(false);

        expect(
          objectType.parse({
            name: 'John',
            age: 30,
          }),
        ).toEqual({
          name: 'John',
          age: 30,
        });
      });

      it('should validate arrays', () => {
        const arrayType = createBaseType(Type.Array(Type.String()));

        expect(arrayType.check(['a', 'b', 'c'])).toBe(true);
        expect(arrayType.check([])).toBe(true);
        expect(arrayType.check([1, 2, 3])).toBe(false);
        expect(arrayType.check('abc')).toBe(false);
      });

      it('should validate unions', () => {
        const unionType = createBaseType(Type.Union([Type.String(), Type.Number()]));

        expect(unionType.check('hello')).toBe(true);
        expect(unionType.check(42)).toBe(true);
        expect(unionType.check(true)).toBe(false);
      });

      it('should validate optional properties', () => {
        const optionalType = createBaseType(
          Type.Object({
            required: Type.String(),
            optional: Type.Optional(Type.Number()),
          }),
        );

        expect(optionalType.check({ required: 'test' })).toBe(true);
        expect(
          optionalType.check({
            required: 'test',
            optional: 42,
          }),
        ).toBe(true);
        expect(
          optionalType.check({
            required: 'test',
            optional: 'nope',
          }),
        ).toBe(false);
        expect(optionalType.check({})).toBe(false);
      });
    });

    describe('errors method', () => {
      it('should return empty array for valid values', () => {
        const type = createBaseType(Type.String());
        expect(type.errors('valid')).toEqual([]);
      });

      it('should return error messages for invalid values', () => {
        const type = createBaseType(Type.String());
        const errors = type.errors(123);
        expect(errors.length).toBeGreaterThan(0);
        expect(errors[0]).toContain('string');
      });

      it('should return multiple errors for complex types', () => {
        const type = createBaseType(
          Type.Object({
            name: Type.String(),
            age: Type.Number(),
          }),
        );
        const errors = type.errors({
          name: 123,
          age: 'invalid',
        });
        expect(errors.length).toBeGreaterThanOrEqual(2);
      });
    });

    describe('decode method', () => {
      it('should decode values', () => {
        const type = createBaseType(Type.String());
        expect(type.decode('hello')).toBe('hello');
      });

      it('should decode complex objects', () => {
        const type = createBaseType(
          Type.Object({
            name: Type.String(),
          }),
        );
        expect(type.decode({ name: 'test' })).toEqual({ name: 'test' });
      });
    });
  });

  describe('createDateType', () => {
    const dateType = createBaseType(createDateType());

    it('should validate Date objects', () => {
      expect(dateType.check(new Date())).toBe(true);
      expect(dateType.check(new Date('2025-01-01'))).toBe(true);
    });

    it('should reject invalid dates', () => {
      expect(dateType.check(new Date('invalid'))).toBe(false);
    });

    it('should reject non-Date values', () => {
      expect(dateType.check('2025-01-01')).toBe(false);
      expect(dateType.check(Date.now())).toBe(false);
      expect(dateType.check(null)).toBe(false);
      expect(dateType.check(undefined)).toBe(false);
    });

    it('should parse valid Date objects', () => {
      const date = new Date('2025-06-15');
      expect(dateType.parse(date)).toBe(date);
    });

    it('should throw for invalid values', () => {
      expect(() => dateType.parse('2025-01-01')).toThrow('Expected a valid Date object');
      expect(() => dateType.parse(new Date('invalid'))).toThrow('Expected a valid Date object');
    });

    it('should return errors for invalid values', () => {
      expect(dateType.errors(new Date())).toEqual([]);
      expect(dateType.errors('not-a-date')).toEqual(['Expected a valid Date object']);
    });

    it('should decode Date objects', () => {
      const date = new Date();
      expect(dateType.decode(date)).toBe(date);
    });
  });

  describe('TypeBoxInfer', () => {
    it('should correctly infer types (compile-time check)', () => {
      const schema = Type.Object({
        name: Type.String(),
        age: Type.Number(),
      });

      type Inferred = TypeBoxInfer<typeof schema>;

      // Runtime check that the type works
      const value: Inferred = {
        name: 'test',
        age: 42,
      };
      expect(value).toEqual({
        name: 'test',
        age: 42,
      });
    });
  });
});

